var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"으아악! 대체 어떤 변태가 이따위로 최적화를 해 놓은 거야!","JPN":"うああ！　一体どこの変態がこんな風に最適化しておいたんだ！","ENG":"Gaaah! Just what kind of psycho optimized the system like this!","TWN":"可惡！是哪個變態進行的優化啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"굴하지 마라, 앨버트! 월급쟁이들의 스파게티 코드에 굴해서는 안 된다!","JPN":"屈するな、アルバート！　サラリーマンどものスパゲティコードに屈してはいけない！","ENG":"Don’t cave in, Albert! You must not cave in to the spaghetti code made by capitalist sheep!","TWN":"不能認輸，亞伯特！我們不能輸給領固定薪的義大利麵式程式碼！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"둘 다 좀 닥쳐! 함선에 엔진 하나 연결하는 것 갖고 왜 이리 시끄러워!","JPN":"二人とも黙って！　艦船にエンジン繋げるくらいでなに騒いでんのよ！","ENG":"Both of you, shut up! Are you connecting the engine to the ship with your mouths?!","TWN":"你們兩個都給我安靜點！不過就是將一個引擎連接到艦船而已，有什麼好哇哇叫的！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L7_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"저 여자애는 왜 저렇게 성질머리가 더럽나 몰라.","JPN":"あの女の子はなんであんなに性格悪いのかな。","ENG":"I don’t know why that girl has such a bad temper.","TWN":"那女的脾氣怎麼這麼差？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"친구, 저런 사람을 <color=#ffd34c>탄산 없는 사이버캣</color>이라고 부른다는 거 알고 있어?","JPN":"友よ、ああいうのを<color=#ffd34c>炭酸の抜けたサイバーキャット</color>って呼ぶの知ってるか？","ENG":"Yo, did you know that people like that are called <color=#ffd34c>fizzled-out Cyber Cat</color>?","TWN":"朋友，你知道嗎？這種人我們通常稱為<color=#ffd34c>沒料的賽博貓</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"오우, 무슨 뜻이야?","JPN":"おお、どういう意味？","ENG":"Oh? What does that mean?","TWN":"哇喔，這什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"폼도 떨어졌는데 성질머리는 더러운 해커를 가리키는 말이야.","JPN":"腕も落ちてんのに、性根が腐っているハッカーのことをそういうんだ。","ENG":"A hacker with no skill and a bad temper.","TWN":"就是指那些虛有其表，然後性格很差的駭客。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HACKER_NPC_NULL_BOTH","text":{"KOREA":"와하하하하!!","JPN":"わはははは！！","ENG":"Ahahahahaha!!","TWN":"哈哈哈哈哈哈哈！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……두 놈 다 미사일에 매달아서 날려 버리고 싶네, 진짜.","JPN":"……二人ともミサイルに縛ってぶっ飛ばしたいわ、マジで。","ENG":"...I really want to tie those two on a missile and launch it.","TWN":"……你們是想被掛在導彈上射出去是吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래도 어떻게든 탑재는 마무리됐고, 기동 시퀀스만 만져 주면 되려나……","JPN":"でもなんとか搭載できたし、起動シーケンスさえいじればいいか……","ENG":"Anyway, we’ve finished mounting the engine and just need to deal with the start up sequence...","TWN":"總之已經搭載完畢，接下來就是改一下啟動函數……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"에휴, 국방부에 멀쩡한 프로그래머가 한 명만 더 있었어도 저것들은 안 불렀을 텐데.","JPN":"はあ、国防省にまともなプログラマーがもう一人いればあいつらは呼ばなくて済んだのに。","ENG":"Ugh, if only the Department of Defense had one more normal programmer, we wouldn’t have had to use those idiots.","TWN":"哀～要是國防部再多一個堪用的工程師，也不至於找那種傢伙來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"응? 뭐야? 침식파가…….","JPN":"うん？　なに？　侵食波が……","ENG":"Huh? What’s this? The Corruption Ray...","TWN":"嗯？怎麼會？侵蝕波……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":" 5종?!","JPN":" 第5種！？","ENG":" Category 5?!","TWN":"5類？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실비아, 비상 사태다! 외부 카메라 확인해!","JPN":"シルビア、非常状態だ！　外部カメラを確認しろ！","ENG":"Sylvia, it’s an emergency! Check the external cameras!","TWN":"希爾維亞，緊急狀況！立刻確認外部鏡頭！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 저건…? 설마 저게 감찰부대 사람들이라고?","JPN":"なんだ、あれ……？　まさかあれが監察部隊の隊員？","ENG":"What on earth is that...? Don’t tell me... Are those the Inspection Corps soldiers?","TWN":"這是…？該不會是監察組的人？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 슬라임도 아니고 왜 한 덩어리가 된 거야?!","JPN":"いや、スライムでもあるまいし、なんでひとかたまりになってるわけ！？","ENG":"Why are they jumbled together in a single mass?! They’re not even melted together into slime!","TWN":"不對，怎麼不是黏液而是一整團？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"원인은 저희도 모르겠습니다!","JPN":"原因は私たちにもわかりません！","ENG":"We don’t know why, either!","TWN":"我們也不清楚原因！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만…… 저 부정형 개체가 방출하는 침식파는 명백하게 4종을 초과하고 있어요!","JPN":"ですが……あの不定形の個体が放出する侵食波は確かに第4種を越えています！","ENG":"But... the Corruption Ray that amorphous entity is emitting is clearly exceeding Category 4!","TWN":"只知道……釋放出不規則個體的侵蝕波超過4類！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말도 안 돼! 5종이면 저게 네임리스 원이랑 동급이란 뜻이잖아!","JPN":"あり得ないわ！　第5種なら、あれがネームレスワンと同レベルってことでしょ！","ENG":"That’s impossible! If it’s Category 5, that thing is on the same level as the Nameless One!","TWN":"這怎麼可能！5類的話，不就和無名1同等級嗎！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그, 그런 괴물이 어떻게 저렇게 갑자기 나타나! 그 말을 나더러 믿으란 거야?!","JPN":"あ、あんなバケモンがどうやっていきなり現れるのよ！　それを信じろっていうの！？","ENG":"H-how can a monster like that just appear? Do you really expect me to believe that?!","TWN":"那…那種怪物怎麼會突然就冒出來！怎麼可能？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"설명해 줄 시간 없어, 실비아. 녀석이 엔터프라이즈 쪽으로 움직인다.","JPN":"説明してる暇はないぞ、シルビア。ヤツがエンタープライズの方へ向かってる。","ENG":"I don’t have time to explain, Sylvia. It’s moving towards the Enterprise.","TWN":"希爾維亞，我沒時間跟你解釋，那傢伙正朝企業號移動中。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"스톰 브링거가 필요해. 지금 당장 사출해 줘.","JPN":"ストームブリンガーが必要だ。今すぐ射出してくれ。","ENG":"We need Stormbringer. Please eject it immediately.","TWN":"我需要興風者，立刻送來給我！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대령, 잭 팟이 연속으로 두 번이나 터지길 기대하는 건 아니겠지?","JPN":"大佐、連続2回のジャックポットを期待してるんじゃないだろうな？","ENG":"Colonel, don’t tell me that you’re hoping for a jackpot two times in a row.","TWN":"上校，你該不會以為幸運女神會連續眷顧你兩次吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지난번에 스톰 브링거가 폭발하지 않은 건 순전히 내 실력과 운이 좋아서였어.","JPN":"この前ストームブリンガーが爆発しなかったのは、単に俺の実力と運の良さのおかげだったんだ。","ENG":"The reason why Stormbringer didn’t blow up last time was purely a combination of my skill and luck.","TWN":"上次興風者沒有爆炸，完全是因為我能力好，加上運氣好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 행운은 두 번 발생하지 않아.","JPN":"あんな幸運は二度も起きないぞ。","ENG":"That kind of luck doesn’t come around twice.","TWN":"好運是不會發生兩次的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"흥, 용병들은 잘 모르겠지만 이 제이크 워커에게 운이란 건 말이지……","JPN":"ふん、傭兵は知らないだろうが、このジェイク・ウォーカーにとって運ってもんはな……","ENG":"Hmph, maybe not to mercenaries, but to me, Jake Walker, luck...!","TWN":"哼，傭兵懂什麼，對我傑克·沃克而言，運氣這種事……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"멱살을 잡고 끌고 오는 거라고!","JPN":"胸ぐら掴んで引っ張ってくるもんなんだよ！","ENG":"Is meant to be dragged by the collar!","TWN":"是由我決定的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……이 멍청이가 비유를 못 알아듣잖아!","JPN":"……このアホはたとえも理解できねぇのか！","ENG":"...This idiot doesn’t get the expression!","TWN":"……你這傻瓜在說什麼鬼話，聽不懂啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"미안하지만 대령, 행운의 멱살은 다음 번에 잡도록 하지.","JPN":"すまないが大佐、幸運の胸ぐらはまた今度掴むとしよう。","ENG":"Sorry Colonel, but let’s drag luck by its collar next time.","TWN":"上校，不好意思，我們下次在賭運氣吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L44_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 하지만 이대로 두면 놈이 엔터프라이즈를 파괴할 겁니다.","JPN":"ですが司令官､このまま放っておくとヤツがエンタープライズを破壊します。","ENG":"But Commander, if we let that thing be, it will destroy the Enterprise.","TWN":"司令官，但不想點辦法的話，那傢伙會毀掉整艘企業號的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"걱정말게.","JPN":"心配はいらない。","ENG":"Don’t worry.","TWN":"放心吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 델타세븐 최강의 카드이긴 해도, 여기에 자네만 있는 건 아니거든.","JPN":"君がデルタセブン最強の札ではあるが、ここには君ばかりではないからな。","ENG":"You may be Delta Seven’s trump card, but you’re not the only one.","TWN":"雖然你是第七三角洲的最強王牌，但這裡可不是只有你而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"노장의 실력을 한 번 믿어 보게나.","JPN":"ベテランの実力を信じてみろ。","ENG":"Leave this to the veteran.","TWN":"你就相信一次老將的實力吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아, 엔터프라이즈 쿼드의 엔진을 기동할 수 있겠나?","JPN":"シルビア、エンタープライズクワッドのエンジンを起動できるか？","ENG":"Sylvia, will you be able to activate the Enterprise’s Quad Engines?","TWN":"希爾維亞，企業4號的引擎可以啟動嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"최대출력은 힘들어. 하지만 30% 정도라면……","JPN":"最大出力は無理。でも30％ぐらいなら……","ENG":"Maximum output will be difficult. But 30% might be possible...?","TWN":"最大輸出會有難度，差不多30%……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 정도면 충분해.","JPN":"その程度で十分だ。","ENG":"That will be enough.","TWN":"那樣就夠了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 리플…… 아니, 룩 양에게 동력 전달 시스템을 개방해 주게.","JPN":"それとリプレ……いや、ルーク君に動力伝達システムを開放してやれ。","ENG":"Also, open the power delivery system to Repl... no, Miss Rook.","TWN":"另外對克……不對，是對城堡開放動力傳達系統。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"함선의 동력 전달 시스템을 외부인에게 개방하라고?","JPN":"艦船の動力伝達システムを部外者に開放しろっていうの？","ENG":"You want me to open the ship’s power delivery system to an outsider?","TWN":"要向外人開放艦船的動力傳達系統嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"거긴 정말 민감한 곳이야. 잘못 건드리면 함선이 통째로 폭발할 거라고!","JPN":"そこは本当に敏感なところだよ。一歩間違えたら艦船が丸ごと爆発する！","ENG":"That’s a very sensitive area. One wrong move and the ship will be sent to oblivion!","TWN":"那裡要很小心，萬一一個沒弄好，艦船可是會爆炸的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"걱정 마렴, 실비아.","JPN":"心配するな、シルビア。","ENG":"Don’t worry, Sylvia.","TWN":"希爾維亞，你放心，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그녀는 이런 시스템 운용의 달인이니까.","JPN":"彼女はこのようなシステムの達人だからな。","ENG":"She’s a master at handling these types of systems.","TWN":"她是運用這種系統的達人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 그녀가 가진 특별한 능력을 이용하면 함선 엔진의 동력을 가르강튀아에 직접 공급할 수 있네.","JPN":"そして彼女の特別な能力を用いると、艦船エンジンの動力をガルガンティアに直接供給することもできる。","ENG":"Also, she can route the ship engine’s power supply directly to Garguantia using her special abilities.","TWN":"而且只要利用她的特殊能力，就可以將艦船的引擎動力直接供應給加爾剛迪亞。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그, 그게 정말이야? 저 엄청난 에너지를 원격으로 공급한다고?","JPN":"そ、それ本当？　あんなとんでもないエネルギーを遠隔で供給するの？","ENG":"R-really? She can remotely supply that massive amount of energy?","TWN":"真…真的嗎？可以遠距離供應那麼龐大的動能？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 정도의 공간 능력을 가진 건…… 젊었을 때의 아줌마 정도 밖에 못 본 것 같은데.","JPN":"そのくらいの空間能力は……若い頃のおばさんくらいしか見てないんだけど。","ENG":"A space-altering ability of that scale... The only one I’ve seen who comes even close to that is probably you during your prime, Maria.","TWN":"除了年輕時的大嬸……我還沒見過第二人有這麼厲害的空間能力。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"믿어보게나. 나만큼, 아니 그 이상으로 잘 해낼 테니까.","JPN":"信じてみろ。私のように、いや、それ以上にうまくやれるはずだ。","ENG":"Trust me. She’ll do as well, no, even better than I did.","TWN":"就信她一次吧，她一定會跟我一樣，不，她會做得比我更好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이씨, 몰라! 시스템 개방은 해 주겠지만 뒷일은 나도 책임 못 져!","JPN":"ああ、もうわかんない！　システムは開放するけど、あとは私も責任取れないよ！","ENG":"Ugh, fine! I’ll open it, but don’t blame me for whatever happens next!","TWN":"可惡！就這樣吧！我會替她開放系統，但後面的事我可不管！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"오……! 오오오……! 온다……!","JPN":"く……！　くくく……！　来る……！","ENG":"Ohh...! Ohhhhhh...!! Here it comes!","TWN":"喔……！喔喔喔……！來啦……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"역시 우리에게는 음지가 어울려! 이래서 양지로 올라오면 안 됐다니까!","JPN":"やっぱり私たちには日影がちょうどいい！　これだから日向には出たくなかったんだよ！","ENG":"I knew we belonged underground! This is what happens when you come to the surface!","TWN":"我們果然還是比較適合躲在暗地裡！不能曝光啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아아아악!!","JPN":"きゃああああ！！","ENG":"Eeeeek!!","TWN":"哇啊啊啊！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"고, 공격 받고 있잖아요! 이러다 함선째로 당하겠어요!","JPN":"こ、攻撃されてるじゃないですか！　これじゃあ艦船ごとやられますよ！","ENG":"W-we’re under attack! The entire ship will be done at this rate!","TWN":"敵…敵人打過來啦！再這樣下去整艘艦船都會完蛋的啦！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"시스템 접속 완료.","JPN":"システム接続完了。","ENG":"System access, complete.","TWN":"系統連接完畢。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L23_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"알큐비에레 프로토콜 전환.","JPN":"アルクビエレプロトコル転換。","ENG":"Switching to Alcubierre Protocol.","TWN":"轉換協定引擎。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L24_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"타깃, 시공가속기 가르강튀아. 초공간 동력 공급 개시.","JPN":"ターゲット、時空加速器ガルガンティア。超空間動力供給開始。","ENG":"Target: Time-space accelerator Garguantia. Initiating hyperspace energy transfer.","TWN":"目標，時空加速器 加爾剛迪亞，開始供應超空間動力。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>똑바로 쳐다보지 마! 의식을 잃은 병사들이 속출하고 있다!</color>","JPN":"<color=#ffd34c>まっすぐ見つめるな！　意識を失う兵士が続出してるぞ！</color>","ENG":"<color=#ffd34c>Don’t look at it directly! Too many troopers have lost consciousness!</color>","TWN":"<color=#ffd34c>不要盯著怪物看！一直有士兵昏過去！</color>"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>자, 잠깐! 저기 엔터프라이즈의 갑판 위에!</color>","JPN":"<color=#ffd34c>ま、待て！　あそこ、エンタープライズのデッキの上！</color>","ENG":"<color=#ffd34c>H-hold on! Look there, on the deck of the Enterprise!</color>","TWN":"<color=#ffd34c>等等！企業號的甲板上！</color>"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안토노프 중장님…...! 중장님께서 오셨다!!</color>","JPN":"<color=#ffd34c>アントノフ中将……！　中将がおいでになった！！</color>","ENG":"<color=#ffd34c>Lieutenant General Antonov...! The Lieutenant General is here!!</color>","TWN":"<color=#ffd34c>安東諾夫中將……！是中將！！</color>"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"지난번에는 조금 아쉬웠지.","JPN":"この前は少々残念だったな。","ENG":"Last time was a little unsatisfactory.","TWN":"上次有點可惜，"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"하지만 이번엔 다를 거다.","JPN":"だが、今度は違う。","ENG":"But things are different now.","TWN":"但這次可不會像上次一樣！"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"망할 초월자들의 도움이 없더라도……","JPN":"超越者どもの助けなしでも……","ENG":"Even without the help of those damn superhumans...","TWN":"就算沒有那些超人的幫助……"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"우리가 쌓아 온 힘으로, 우리에게 살아남을 자격이 있다는 걸.","JPN":"私たちが積んできた力で、私たちは生き残る資格があるということを。","ENG":"Using the power that we’ve built up, we’ll show you that we deserve to live.","TWN":"我會用我們過去所累積的實力證明，"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"증명해 주지!","JPN":"証明してやろう！","ENG":"Witness that power now!","TWN":"我們是有資格活下來的！"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};